import { LANGUAGE_LABELS, LanguageCode } from '@/types/enums';
import { Button, Modal, Tag, Typography } from 'antd';

const LANGUAGE_OPTIONS = Object.entries(LANGUAGE_LABELS).map(
  ([value, label]) => ({ value, label })
);

export const LanguagePickerModal: React.FC<{
  open: boolean;
  title: string;
  onSelect: (lang: LanguageCode) => void;
  onClose: () => void;
}> = ({ open, title, onSelect, onClose }) => {
  return (
    <Modal
      title={title}
      open={open}
      footer={null}
      onCancel={onClose}
      width={450}
      destroyOnHidden
    >
      <Typography.Text
        type="secondary"
        style={{ display: 'block', marginBottom: 10 }}
      >
        Choose the language to translate the content into.
      </Typography.Text>
      <div style={{ maxHeight: '400px', overflowY: 'auto' }}>
        {LANGUAGE_OPTIONS.map(({ value, label }) => (
          <Button
            block
            size="middle"
            onClick={() => onSelect(value as LanguageCode)}
            style={{
              gap: 15,
              padding: 16,
              borderRadius: 0,
              marginBottom: 4,
              textAlign: 'left',
              background: 'transparent',
            }}
          >
            <Tag
              style={{
                margin: 0,
                minWidth: 48,
                textAlign: 'center',
                fontFamily: 'monospace',
                fontSize: 11,
                letterSpacing: 0.5,
                flexShrink: 0,
              }}
            >
              {value.toUpperCase()}
            </Tag>
            <Typography.Text style={{ flex: 1 }}>{label}</Typography.Text>
          </Button>
        ))}
      </div>
    </Modal>
  );
};
