import { LanguagePickerModal } from '@/components/NovelActionPanel/LanguagePickerModal';
import type { Job, Novel } from '@/types';
import { LANGUAGE_LABELS, LanguageCode } from '@/types/enums';
import { stringifyError } from '@/utils/errors';
import { DownOutlined, GlobalOutlined } from '@ant-design/icons';
import type { DropDownProps, MenuProps } from 'antd';
import { Button, Dropdown, message, Typography } from 'antd';
import axios from 'axios';
import { useEffect, useMemo, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';

export const NovelLanguageSelection: React.FC<
  Omit<DropDownProps, 'menu'> & {
    novel: Novel;
  }
> = ({ novel, ...props }) => {
  const navigate = useNavigate();
  const [messageApi, contextHolder] = message.useMessage();
  const { language } = useParams<{ language?: LanguageCode }>();

  const [available, setAvailable] = useState<LanguageCode[]>([]);

  const [translating, setTranslating] = useState(false);
  const [showTranslateModal, setShowTranslateModal] = useState(false);

  useEffect(() => {
    axios
      .get<LanguageCode[]>(`/api/novel/${novel.id}/languages`)
      .then(({ data }) => setAvailable(data))
      .catch(() => setAvailable([]));
  }, [novel.id]);

  const languageMenuItems = useMemo(() => {
    const menuItems: MenuProps['items'] = Object.entries(LANGUAGE_LABELS)
      .filter(([key]) => available.includes(key))
      .map(([key, label]) => ({
        key,
        label,
        onClick: () => navigate(`/novel/${novel.id}/${key}`),
      }));
    if (menuItems.length > 0) {
      menuItems.unshift({ type: 'divider' });
    }
    menuItems.unshift({
      key: '__original__',
      label: 'Original',
      onClick: () => navigate(`/novel/${novel.id}`),
    });
    menuItems.push({ type: 'divider' });
    menuItems.push({
      key: '__translate__',
      label: <Typography.Text type="success">Translate</Typography.Text>,
      onClick: () => setShowTranslateModal(true),
    });
    return menuItems;
  }, [available, novel.id, navigate]);

  const handleTranslate = async (lang: LanguageCode) => {
    setShowTranslateModal(false);
    try {
      setTranslating(true);
      const result = await axios.post<Job>('/api/job/create/translate-novels', {
        novel_ids: [novel.id],
        language: lang,
        full: true,
      });
      navigate(`/job/${result.data.id}`);
    } catch (err) {
      messageApi.error(stringifyError(err));
    } finally {
      setTranslating(false);
    }
  };

  return (
    <>
      {contextHolder}
      <Dropdown
        trigger={['click']}
        {...props}
        disabled={translating || props.disabled}
        menu={{
          items: languageMenuItems,
          selectedKeys: [language ?? '__original__'],
        }}
      >
        <Button type={language ? 'primary' : 'default'} ghost={!!language}>
          <GlobalOutlined />
          {(language && LANGUAGE_LABELS[language]) || 'Original'}
          <DownOutlined style={{ fontSize: 9, opacity: 0.6 }} />
        </Button>
      </Dropdown>
      <LanguagePickerModal
        open={showTranslateModal}
        title={'Translate Full Novel'}
        onSelect={handleTranslate}
        onClose={() => setShowTranslateModal(false)}
      />
    </>
  );
};
